<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;class TopupOrder extends Model{protected $fillable=['order_no','user_id','game_id','game_package_id','provider_id','payment_mode','payment_status','order_status','provider_status','player_id','server_id','amount_minor','currency_code','provider_order_id','provider_response','message'];protected $casts=['provider_response'=>'array'];public function user(){return $this->belongsTo(User::class);}public function game(){return $this->belongsTo(Game::class);}public function package(){return $this->belongsTo(GamePackage::class,'game_package_id');}public function provider(){return $this->belongsTo(Provider::class);}}
